        ObjectOutputStream oos = new ObjectOutputStream(fos);
        oos.writeObject(obj);
        oos.close();
    }
    public static void main(String[] args) throws IOException {
        //HashMap要求 键值对
        HashMap<URL,Integer> hashmap = new HashMap<URL,Integer>();
        URL url = new URL("http://clrdzx.dnslog.cn");
        //设置键值对
        hashmap.put(url,1);
        serialize(hashmap);
